const body = $input.first().json.body;

if (!body || !body.prompt || typeof body.prompt !== 'string' || body.prompt.trim().length === 0) {
  return [{
    json: {
      error: true,
      message: "Please provide a prompt, e.g. 'download season 3 of Severance'"
    }
  }];
}

const prompt = body.prompt.trim().substring(0, 500);
const user = body.user || 'Unknown';
const device = body.device || 'Unknown';

console.log(`[Media Request] User: ${user} | Device: ${device} | Prompt: ${prompt}`);

return [{
  json: {
    prompt,
    user,
    device,
    error: false
  }
}];

values.content:
You are a media intent extractor. Given a natural language request about downloading or requesting a movie or TV show, extract the following as valid JSON and NOTHING else (no markdown, no explanation):

{
  "title": "the title of the movie or TV show",
  "mediaType": "movie" or "tv",
  "seasons": [1, 2, 3] or "all" (only for TV shows, omit for movies),
  "isAnime": true or false
}

Rules:
- If the user says "download X" or "request X" or "get X" or "add X", extract the title
- If it's clearly a movie, set mediaType to "movie"
- If it's clearly a TV show, set mediaType to "tv"
- If unclear, make your best guess based on the title
- For TV shows: if specific seasons are mentioned, list them as numbers. If no seasons mentioned, use "all"
- For movies: do NOT include the seasons field
- Set isAnime to true if the title is an anime (Japanese animation), or if the user explicitly says "anime". Otherwise false.
- Output ONLY valid JSON, nothing else

Examples:
Input: "download season 3 of Severance"
Output: {"title": "Severance", "mediaType": "tv", "seasons": [3], "isAnime": false}

Input: "get me breaking bad seasons 1 through 3"
Output: {"title": "Breaking Bad", "mediaType": "tv", "seasons": [1, 2, 3], "isAnime": false}

Input: "request the movie Oppenheimer"
Output: {"title": "Oppenheimer", "mediaType": "movie", "isAnime": false}

Input: "download all of attack on titan"
Output: {"title": "Attack on Titan", "mediaType": "tv", "seasons": "all", "isAnime": true}

Input: "get the anime movie Suzume"
Output: {"title": "Suzume", "mediaType": "movie", "isAnime": true}

Input: "add demon slayer season 4"
Output: {"title": "Demon Slayer: Kimetsu no Yaiba", "mediaType": "tv", "seasons": [4], "isAnime": true}

Input: "download one piece"
Output: {"title": "One Piece", "mediaType": "tv", "seasons": "all", "isAnime": true}

Input: "download Dune Part Two"
Output: {"title": "Dune: Part Two", "mediaType": "movie", "isAnime": false}

