// Parse and validate LLM JSON response
const input = $input.first().json;
const user = $('Validate Input').first().json.user;
const device = $('Validate Input').first().json.device;

// Gemini returns content.parts[0].text
let llmText;
if (input.content && input.content.parts && input.content.parts[0] && input.content.parts[0].text) {
  llmText = input.content.parts[0].text;
} else if (typeof input.text === 'string') {
  llmText = input.text;
} else if (typeof input.content === 'string') {
  llmText = input.content;
} else {
  llmText = JSON.stringify(input);
}

// Strip markdown code fences if present
llmText = llmText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let intent;
try {
  intent = JSON.parse(llmText);
} catch (e) {
  return [{
    json: {
      error: true,
      message: "Sorry, I couldn't understand that request. Try something like: 'download season 3 of Severance'",
      user,
      device
    }
  }];
}

if (!intent.title || !intent.mediaType) {
  return [{
    json: {
      error: true,
      message: "Sorry, I couldn't extract a title from your request. Try being more specific.",
      user,
      device
    }
  }];
}

if (!['movie', 'tv'].includes(intent.mediaType)) {
  intent.mediaType = 'tv';
}

return [{
  json: {
    title: intent.title,
    mediaType: intent.mediaType,
    seasons: intent.seasons || null,
    isAnime: intent.isAnime === true,
    encodedTitle: encodeURIComponent(intent.title),
    user,
    device,
    error: false
  }
}];

// Process Seerr search results and build request
const searchData = $input.first().json;
const intent = $('Parse LLM Response').first().json;
const results = searchData.results || [];

if (results.length === 0) {
  return [{
    json: {
      error: true,
      action: 'respond',
      message: "Couldn't find '" + intent.title + "' on Seerr. Check the title and try again.",
      user: intent.user,
      device: intent.device
    }
  }];
}

// Find best matching result (prefer exact mediaType match)
let match = results.find(r => r.mediaType === intent.mediaType) || results[0];
const title = match.name || match.title;
const mediaType = match.mediaType;
const tmdbId = match.id;

// Check availability status
const status = match.mediaInfo?.status || 1;

if (status === 5) {
  return [{
    json: {
      error: false,
      action: 'respond',
      message: "'" + title + "' is already fully available on Plex!",
      user: intent.user,
      device: intent.device
    }
  }];
}

if (status === 2 || status === 3) {
  return [{
    json: {
      error: false,
      action: 'respond',
      message: "'" + title + "' has already been requested and is being processed.",
      user: intent.user,
      device: intent.device
    }
  }];
}

// Build request payload
let requestBody = {
  mediaType: mediaType,
  mediaId: tmdbId
};

// Route to anime servers if detected as anime
// Seerr server IDs: Sonarr Anime=2, Radarr Anime=2
if (intent.isAnime) {
  if (mediaType === 'tv') {
    requestBody.serverId = 2; // Sonarr Anime
  } else {
    requestBody.serverId = 2; // Radarr Anime
  }
}

if (mediaType === 'tv') {
  if (intent.seasons === 'all' || intent.seasons === null) {
    requestBody.seasons = 'all';
  } else if (Array.isArray(intent.seasons)) {
    requestBody.seasons = intent.seasons;
  }
}

const seasonText = mediaType === 'tv'
  ? (requestBody.seasons === 'all' ? ' (all seasons)' : ' season(s) ' + (Array.isArray(requestBody.seasons) ? requestBody.seasons.join(', ') : requestBody.seasons))
  : '';
const animeText = intent.isAnime ? ' [anime]' : '';

return [{
  json: {
    error: false,
    action: 'request',
    requestBody,
    title,
    seasonText,
    animeText,
    user: intent.user,
    device: intent.device
  }
}];

// Build final success response
const prev = $('Process Results').first().json;
const seerrResponse = $input.first().json;

let message;
if (seerrResponse.statusCode && seerrResponse.statusCode >= 400) {
  message = "Failed to request '" + prev.title + "': " + (seerrResponse.message || 'Seerr returned an error');
  return [{
    json: {
      success: false,
      message,
      requestedBy: prev.user,
      device: prev.device
    }
  }];
}

message = "Requested '" + prev.title + "'" + prev.seasonText + prev.animeText;

return [{
  json: {
    success: true,
    message,
    requestedBy: prev.user,
    device: prev.device
  }
}];
